{
  "name": "Urvashi - AI Style Swap",
  "description": "An AI-powered style transfer app that extracts prompts from one image and applies them to your photo using Gemini Nano Banana (gemini-2.5-flash-image). Meet Urvashi, your helpful AI companion.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  image?: string;
  timestamp: Date;
}

export enum AppStep {
  IDLE = 'IDLE',
  ANALYZING_STYLE = 'ANALYZING_STYLE',
  READY_FOR_SELFIE = 'READY_FOR_SELFIE',
  GENERATING_FINAL = 'GENERATING_FINAL',
  COMPLETED = 'COMPLETED'
}

export interface StyleData {
  prompt: string;
  styleImage: string;
}

import { GoogleGenAI } from "@google/genai";
import { MODEL_TEXT, MODEL_IMAGE, URVASHI_SYSTEM_PROMPT, EXTRACT_PROMPT_INSTRUCTION } from "../constants";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const extractPromptFromImage = async (base64Image: string): Promise<string> => {
  const ai = getAIClient();
  const imagePart = {
    inlineData: {
      mimeType: 'image/png',
      data: base64Image.split(',')[1] || base64Image,
    },
  };

  const response = await ai.models.generateContent({
    model: MODEL_TEXT,
    contents: {
      parts: [
        { text: EXTRACT_PROMPT_INSTRUCTION },
        imagePart
      ]
    },
    config: {
      systemInstruction: URVASHI_SYSTEM_PROMPT
    }
  });

  return response.text || "A beautiful cinematic scene.";
};

export const applyStyleToUserImage = async (userImageBase64: string, stylePrompt: string): Promise<string> => {
  const ai = getAIClient();
  const imagePart = {
    inlineData: {
      mimeType: 'image/png',
      data: userImageBase64.split(',')[1] || userImageBase64,
    },
  };

  // Constructing the final prompt to ensure body/face preservation
  const finalPrompt = `Transform the environment, style, and lighting of this image to match this description: ${stylePrompt}. 
  CRITICAL: Keep the person's face and body features exactly the same as in the provided image. Only change the background, lighting, and artistic style.`;

  const response = await ai.models.generateContent({
    model: MODEL_IMAGE,
    contents: {
      parts: [
        imagePart,
        { text: finalPrompt }
      ]
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1"
      }
    }
  });

  let imageUrl = "";
  if (response.candidates && response.candidates[0].content.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }
  }

  if (!imageUrl) throw new Error("Could not generate image");
  return imageUrl;
};

export const getUrvashiReply = async (message: string, context?: string): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: MODEL_TEXT,
    contents: `User says: ${message}${context ? ` | Context: ${context}` : ''}`,
    config: {
      systemInstruction: URVASHI_SYSTEM_PROMPT
    }
  });
  return response.text || "Arre yaar, network issue shayad!";
};

import React, { useState, useRef, useEffect } from 'react';
import { AppStep, ChatMessage } from './types';
import { extractPromptFromImage, applyStyleToUserImage, getUrvashiReply } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'assistant',
      content: 'Hii! Mai Urvashi hoon. Mujhse koi bhi image share karo jiska style tumhe pasand ho, mai tumhara face usme fit kar dungi! 😍',
      timestamp: new Date()
    }
  ]);
  const [step, setStep] = useState<AppStep>(AppStep.IDLE);
  const [stylePrompt, setStylePrompt] = useState<string>('');
  const [styleImage, setStyleImage] = useState<string>('');
  const [userImage, setUserImage] = useState<string>('');
  const [finalImage, setFinalImage] = useState<string>('');
  const [isLoading, setIsLoading] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const addMessage = (role: 'user' | 'assistant', content: string, image?: string) => {
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role,
      content,
      image,
      timestamp: new Date()
    }]);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;

      if (step === AppStep.IDLE) {
        // Initial Style Image Upload
        setIsLoading(true);
        addMessage('user', 'Ye dekho, ye style mast lag raha hai!', base64);
        setStyleImage(base64);
        setStep(AppStep.ANALYZING_STYLE);

        try {
          const prompt = await extractPromptFromImage(base64);
          setStylePrompt(prompt);
          const reply = await getUrvashiReply("Maine image upload ki hai, style analyze karo.", `Prompt extracted: ${prompt}`);
          addMessage('assistant', reply);
          addMessage('assistant', "Ab apni ek saaf photo (selfie) bhejo, mai tumhe isi style me convert kar dungi. ❤️");
          setStep(AppStep.READY_FOR_SELFIE);
        } catch (err) {
          addMessage('assistant', "Oops, style samajhne me thodi dikkat hui. Phir se try karein?");
          setStep(AppStep.IDLE);
        } finally {
          setIsLoading(false);
        }
      } else if (step === AppStep.READY_FOR_SELFIE) {
        // User's Face Image Upload
        setIsLoading(true);
        addMessage('user', 'Ye rahi meri photo!', base64);
        setUserImage(base64);
        setStep(AppStep.GENERATING_FINAL);

        try {
          const generated = await applyStyleToUserImage(base64, stylePrompt);
          setFinalImage(generated);
          const reply = await getUrvashiReply("Meri photo convert karo.", "Final image generated successfully.");
          addMessage('assistant', "OMG! Tum toh kamaal lag rahe ho is style me! Dekho toh sahi! 🔥");
          addMessage('assistant', "Ye lo tumhari stylized photo:", generated);
          setStep(AppStep.COMPLETED);
        } catch (err) {
          addMessage('assistant', "Sachi bataun toh thoda error aa gaya generate karne me. Dobara bhejoge?");
          setStep(AppStep.READY_FOR_SELFIE);
        } finally {
          setIsLoading(false);
        }
      }
    };
    reader.readAsDataURL(file);
  };

  const resetApp = () => {
    setStep(AppStep.IDLE);
    setStylePrompt('');
    setStyleImage('');
    setUserImage('');
    setFinalImage('');
    addMessage('assistant', "Chalo, koi nayi image try karte hain! Pehle koi style image bhejo.");
  };

  return (
    <div className="flex flex-col h-screen max-w-2xl mx-auto border-x border-gray-800 bg-[#1e1f20]">
      {/* Header */}
      <header className="p-4 border-b border-gray-800 flex items-center justify-between bg-[#131314] sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-pink-500 to-violet-600 flex items-center justify-center text-white font-bold">
            U
          </div>
          <div>
            <h1 className="font-bold text-lg leading-tight">Urvashi AI</h1>
            <p className="text-xs text-green-400">Online & Active</p>
          </div>
        </div>
        <button 
          onClick={resetApp}
          className="text-gray-400 hover:text-white transition-colors text-sm px-3 py-1 rounded-full border border-gray-700"
        >
          Reset
        </button>
      </header>

      {/* Chat Area */}
      <main className="flex-1 overflow-y-auto p-4 space-y-6 scrollbar-thin scrollbar-thumb-gray-800">
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-4 ${
              m.role === 'user' 
                ? 'bg-[#37393b] text-white rounded-tr-none' 
                : 'bg-transparent text-gray-200'
            }`}>
              {m.role === 'assistant' && (
                <div className="text-xs font-semibold text-pink-400 mb-1">Urvashi</div>
              )}
              <p className="text-sm leading-relaxed whitespace-pre-wrap">{m.content}</p>
              {m.image && (
                <div className="mt-3 overflow-hidden rounded-lg border border-gray-700 shadow-xl">
                  <img src={m.image} alt="Uploaded content" className="w-full object-contain max-h-[400px]" />
                </div>
              )}
              <div className="text-[10px] mt-2 opacity-40 text-right">
                {m.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-transparent text-gray-200 p-4 rounded-2xl">
              <div className="flex gap-1">
                <div className="w-2 h-2 bg-pink-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                <div className="w-2 h-2 bg-pink-500 rounded-full animate-bounce" style={{ animationDelay: '200ms' }}></div>
                <div className="w-2 h-2 bg-pink-500 rounded-full animate-bounce" style={{ animationDelay: '400ms' }}></div>
              </div>
              <p className="text-xs text-gray-400 mt-2">
                {step === AppStep.ANALYZING_STYLE ? 'Style scan kar rahi hoon...' : 'Bas thoda sa aur... magic ho raha hai!'}
              </p>
            </div>
          </div>
        )}
        <div ref={chatEndRef} />
      </main>

      {/* Input Area */}
      <footer className="p-4 bg-[#131314] border-t border-gray-800">
        <div className="relative group">
          <label className="flex items-center justify-between w-full bg-[#1e1f20] hover:bg-[#282a2c] transition-colors rounded-2xl px-6 py-4 cursor-pointer border border-transparent focus-within:border-pink-500">
            <span className="text-gray-400 text-sm">
              {step === AppStep.IDLE ? 'Style image upload karo...' : 'Apni photo upload karo...'}
            </span>
            <div className="flex items-center gap-3">
              <i className="fa-solid fa-camera text-pink-500 text-lg"></i>
              <div className="bg-pink-600 hover:bg-pink-700 text-white w-8 h-8 rounded-full flex items-center justify-center transition-all">
                <i className="fa-solid fa-plus text-sm"></i>
              </div>
            </div>
            <input 
              type="file" 
              accept="image/*" 
              className="hidden" 
              onChange={handleFileUpload}
              disabled={isLoading || step === AppStep.COMPLETED}
            />
          </label>
        </div>
        <p className="text-[10px] text-center text-gray-500 mt-3 uppercase tracking-widest font-bold">
          Powered by Gemini Nano Banana 🍌
        </p>
      </footer>
    </div>
  );
};

export default App;

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  image?: string;
  isPrompt?: boolean;
  timestamp: Date;
}

