export default App;

{
  "name": "Urvashi - Identity Lock Prompt Engineer",
  "description": "Professional AI tool to extract image prompts with strict identity preservation for Gemini Nano Banana.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React, { useState, useRef, useEffect } from 'react';
import { AppStep, ChatMessage } from './types';
import { extractPromptFromImage, getUrvashiReply } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      role: 'assistant',
      content: 'Hii! Mai Urvashi hoon. Mujhse koi bhi image share karo, mai uska ek perfect "Identity Lock" prompt nikaal dungi jo tum Gemini Nano Banana me use kar sakte ho. Identity 100% same rahegi! 🧬',
      timestamp: new Date()
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const addMessage = (role: 'user' | 'assistant', content: string, image?: string, isPrompt?: boolean) => {
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      role,
      content,
      image,
      isPrompt,
      timestamp: new Date()
    }]);
  };

  const copyToClipboard = async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      addMessage('assistant', "Prompt copy ho gaya hai! Ab ise Nano Banana me paste kar do. 😉");
    } catch (err) {
      console.error("Failed to copy", err);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Image Validation
    if (!file.type.startsWith('image/')) {
      setError("Arre yaar, ye image file nahi lag rahi. Please photo upload karo.");
      return;
    }

    if (file.size > 15 * 1024 * 1024) { // 15MB limit
      setError("Photo kaafi badi hai! 15MB se choti file try karo.");
      return;
    }

    setError(null);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;

      setIsLoading(true);
      addMessage('user', 'Ye image lock karke iska prompt nikaalo.', base64);

      try {
        const prompt = await extractPromptFromImage(base64);
        const reply = await getUrvashiReply("Maine image bheji hai, prompt nikaalo with Identity Lock.", `Prompt: ${prompt}`);

        addMessage('assistant', reply);
        addMessage('assistant', prompt, undefined, true);

      } catch (err: any) {
        console.error(err);
        addMessage('assistant', "Sorry, error aa gaya! Shayad API issues hain. Thodi der baad try karein?");
      } finally {
        setIsLoading(false);
        e.target.value = ''; // Reset input
      }
    };
    reader.onerror = () => {
      setError("File read karne me error aaya. Please dobara upload karein.");
      setIsLoading(false);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="flex flex-col h-screen max-w-2xl mx-auto border-x border-gray-800 bg-[#0e0e10]">
      {/* Header */}
      <header className="p-4 border-b border-gray-800 flex items-center justify-between bg-[#131314] sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-indigo-500 to-purple-600 flex items-center justify-center text-white font-bold shadow-lg shadow-purple-900/40">
            U
          </div>
          <div>
            <h1 className="font-bold text-lg leading-tight">Identity Lock AI</h1>
            <p className="text-[10px] text-purple-400 font-mono tracking-widest uppercase">Senior AI Engineer Mode</p>
          </div>
        </div>
        <div className="text-[10px] text-gray-500 font-mono hidden sm:block">
          PROMPT ENGINEER v2.0
        </div>
      </header>

      {/* Chat Area */}
      <main className="flex-1 overflow-y-auto p-4 space-y-6 scrollbar-thin scrollbar-thumb-gray-800">
        {messages.map((m) => (
          <div key={m.id} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[92%] rounded-2xl p-4 transition-all duration-300 ${
              m.role === 'user' 
                ? 'bg-[#2b2d31] text-white rounded-tr-none shadow-lg' 
                : m.isPrompt 
                  ? 'bg-[#1a1a1c] border border-purple-500/30 text-purple-100 rounded-tl-none font-mono text-xs leading-relaxed shadow-[0_0_15px_rgba(168,85,247,0.1)]'
                  : 'bg-transparent text-gray-200'
            }`}>
              {m.role === 'assistant' && !m.isPrompt && (
