            <i className="fa-solid fa-camera text-lg"></i>
          </div>
          <input 
            type="file" 
            ref={fileInputRef}
            accept="image/*" 
            className="hidden" 
            onChange={handleFileUpload}
            disabled={isLoading}
          />
        </label>
      </footer>
    </div>
  );
};

export default App;
